// TypeScript implementation for Method Decorators
interface MethodDecoratorsPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processMethodDecorators(item: MethodDecoratorsPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processMethodDecorators({ id: 1, title: 'Method Decorators', status: 'active' }));

